162	/// Run all cases sequentially, dispatching each with per-case temp dir isolation.
163	pub fn rbtdre_run_cases(
164	    cases: &[rbtdre_Case],
165	    colors: &rbtdre_Colors,
166	    fail_fast: bool,
167	    root_temp: &Path,
168	) -> Result<rbtdre_RunResult, String> {
169	    let mut passed = 0usize;
170	    let mut failed = 0usize;
171	    let mut skipped = 0usize;
172	
173	    for case in cases {
174	        let case_dir = root_temp.join(case.name);
175	        std::fs::create_dir_all(&case_dir).map_err(|e| {
176	            format!("rbtd: failed to create case dir '{}': {}", case.name, e)
177	        })?;
178	
179	        let verdict = (case.func)(&case_dir);
180	        rbtdre_write_trace(&case_dir, case.name, &verdict);
181	
182	        match &verdict {
183	            rbtdre_Verdict::Pass => {
184	                eprintln!("{}PASSED:{} {}", colors.green, colors.reset, case.name);
185	                passed += 1;
186	            }
187	            rbtdre_Verdict::Fail(_) => {
188	                eprintln!("{}FAILED:{} {}", colors.red, colors.reset, case.name);
189	                failed += 1;
190	                if fail_fast {
