//     Single-case runner — no charge/quench. List cases or run one.

use std::path::PathBuf;
use std::process::ExitCode;

use rbtd::rbtdrc_crucible::{
    rbtdrc_lookup_fixture, rbtdrc_set_context, rbtdrc_take_context, RBTDRC_FIXTURES,
};
use rbtd::rbtdre_engine::{
    rbtdre_detect_colors, rbtdre_find_case, rbtdre_list_cases, rbtdre_print_summary,
    rbtdre_run_fixture, rbtdre_run_single_case,
};
use rbtd::rbtdri_invocation::{rbtdri_Context, rbtdri_invoke_global};
use rbtd::rbtdrm_manifest::{rbtdrm_verify, RBTDRM_COLOPHON_CRUCIBLE_ACTIVE};

fn main() -> ExitCode {
    let args: Vec<String> = std::env::args().collect();

    if args.get(1).map(|s| s.as_str()) == Some("single") {
        return run_single(&args[2..]);
    }

    run_suite(&args[1..])
}

/// Theurge is always launched by BUK dispatch (via tabtargets like
/// `tt/rbtd-r.FixtureRun.{fixture}.sh`), which exports BURD_TEMP_DIR and
/// BURD_OUTPUT_DIR before invoking the binary. Anchoring theurge's scratch
/// under those dispatch-provided roots — rather than `std::env::temp_dir()` —
/// places forensic artifacts (per-call HTTP captures written by rbgu_http_json
/// under workbench BURD_TEMP_DIR) under `../temp-buk/`, where they survive
/// reboot and systemd-tmpfiles cleanup. Missing or empty values are a
/// dispatch contract violation and abort immediately.
fn read_dispatch_dir(name: &str) -> Result<PathBuf, String> {
    match std::env::var(name) {
        Ok(v) if !v.is_empty() => Ok(PathBuf::from(v)),
        _ => Err(format!(
            "rbtd: {} is not set — theurge must be launched via BUK tabtarget",
            name
        )),
    }
}

struct rbtd_Roots {
    trace_root: PathBuf,
    burv_temp_root: PathBuf,
    burv_output_root: PathBuf,
}

fn allocate_roots() -> Result<rbtd_Roots, String> {
    let burd_temp = read_dispatch_dir("BURD_TEMP_DIR")?;
    let burd_output = read_dispatch_dir("BURD_OUTPUT_DIR")?;

    let trace_root = burd_temp.join("rbtd");
    let burv_temp_root = trace_root.join("burv");
    let burv_output_root = burd_output.join("rbtd").join("burv");

    std::fs::create_dir_all(&trace_root)
        .map_err(|e| format!("rbtd: failed to create trace root '{}': {}", trace_root.display(), e))?;
    std::fs::create_dir_all(&burv_temp_root)
        .map_err(|e| format!("rbtd: failed to create burv temp root '{}': {}", burv_temp_root.display(), e))?;
    std::fs::create_dir_all(&burv_output_root)
        .map_err(|e| format!("rbtd: failed to create burv output root '{}': {}", burv_output_root.display(), e))?;

    Ok(rbtd_Roots { trace_root, burv_temp_root, burv_output_root })
}

// ── Suite runner ─────────────────────────────────────────────

fn run_suite(args: &[String]) -> ExitCode {
    let manifest = match args.first() {
        Some(m) => m,
        None => {
            eprintln!(
                "rbtd: usage: rbtd <manifest> <fixture>\n\
                 theurge must be launched via tabtarget (e.g. tt/rbtd-r.FixtureRun.tadmor.sh)"
            );
            return ExitCode::FAILURE;
        }
    };

    let fixture = match args.get(1) {
        Some(n) => n,
        None => {
            eprintln!("rbtd: no fixture argument — which test fixture to run?");
            return ExitCode::FAILURE;
        }
    };

    if let Err(msg) = rbtdrm_verify(manifest, fixture) {
        eprintln!("{}", msg);
        return ExitCode::FAILURE;
    }

    let project_root = match std::env::current_dir() {
        Ok(p) => p,
        Err(e) => {
            eprintln!("rbtd: cannot determine working directory: {}", e);
            return ExitCode::FAILURE;
        }
    };

    let roots = match allocate_roots() {
        Ok(r) => r,
        Err(msg) => {
            eprintln!("{}", msg);
            return ExitCode::FAILURE;
        }
    };

    let ctx = rbtdri_Context::new(
        &project_root,
        fixture,
        &roots.burv_temp_root,
        &roots.burv_output_root,
    );

    let fixture_def = match rbtdrc_lookup_fixture(fixture) {
        Some(f) => f,
        None => {
            eprintln!(
                "rbtd: fixture '{}' has no registered Fixture — \
                 manifest verification accepted the name but no Fixture static is bound. \
                 Update rbtdrc_lookup_fixture in rbtdrc_crucible.rs.",
                fixture
            );
            return ExitCode::FAILURE;
        }
    };

    rbtdrc_set_context(ctx);

    let colors = rbtdre_detect_colors();
    let run_result = rbtdre_run_fixture(fixture_def, &colors, &roots.trace_root);

    let _ctx = rbtdrc_take_context();

    let result = match run_result {
        Ok(r) => r,
        Err(msg) => {
            eprintln!("rbtd: {}", msg);
            return ExitCode::FAILURE;
        }
    };

    rbtdre_print_summary(&result, &colors);

    if result.failed > 0 {
        eprintln!("rbtd: {} case(s) failed", result.failed);
        ExitCode::FAILURE
    } else {
        ExitCode::SUCCESS
    }
}

// ── Single-case runner ───────────────────────────────────────

fn run_single(args: &[String]) -> ExitCode {
    let manifest = match args.first() {
        Some(m) => m,
        None => {
            eprintln!(
                "rbtd single: usage: rbtd single <manifest> <fixture> [case]\n\
                 omit case to list all cases for the fixture"
            );
            return ExitCode::FAILURE;
        }
    };

    let fixture = match args.get(1) {
        Some(f) => f,
        None => {
            eprintln!("rbtd single: no fixture argument");
            list_fixtures();
            return ExitCode::FAILURE;
        }
    };

    if !RBTDRC_FIXTURES.iter().any(|f| f.name == *fixture) {
        eprintln!("rbtd single: unknown fixture '{}'", fixture);
        list_fixtures();
        return ExitCode::FAILURE;
    }

    if let Err(msg) = rbtdrm_verify(manifest, fixture) {
        eprintln!("{}", msg);
        return ExitCode::FAILURE;
    }

    // Set up execution context early — needed for charge check and case execution
    let project_root = match std::env::current_dir() {
        Ok(p) => p,
        Err(e) => {
            eprintln!("rbtd: cannot determine working directory: {}", e);
            return ExitCode::FAILURE;
        }
    };

    let roots = match allocate_roots() {
        Ok(r) => r,
        Err(msg) => {
            eprintln!("{}", msg);
            return ExitCode::FAILURE;
        }
    };

    // Context is required for every case execution path (rbtdrc_with_ctx).
    // Fixtures with a setup hook (crucible charge) additionally verify their
    // crucible is charged externally — single-case mode never charges.
    let mut ctx = rbtdri_Context::new(
        &project_root,
        fixture,
        &roots.burv_temp_root,
        &roots.burv_output_root,
    );

    let fixture_def = match rbtdrc_lookup_fixture(fixture) {
        Some(f) => f,
        None => {
            eprintln!(
                "rbtd single: fixture '{}' has no registered Fixture",
                fixture
            );
            return ExitCode::FAILURE;
        }
    };

    if fixture_def.setup.is_some() {
        match rbtdri_invoke_global(
            &mut ctx,
            RBTDRM_COLOPHON_CRUCIBLE_ACTIVE,
            &[fixture],
            &[],
        ) {
            Ok(r) if r.exit_code == 0 => {}
            _ => {
                eprintln!(
                    "rbtd single: crucible not charged for '{}'\n\
                     charge first: tt/rbw-cC.Charge.{}.sh",
                    fixture, fixture
                );
                return ExitCode::FAILURE;
            }
        }
    }

    rbtdrc_set_context(ctx);

    let cases = fixture_def.cases;

    // No case argument — list all cases
    let case_name = match args.get(2) {
        None => {
            rbtdre_list_cases(cases);
            return ExitCode::SUCCESS;
        }
        Some(n) => n,
    };

    // Find the case
    let case = match rbtdre_find_case(cases, case_name) {
        Some(c) => c,
        None => {
            eprintln!(
                "rbtd single: case '{}' not found in fixture '{}'",
                case_name, fixture
            );
            rbtdre_list_cases(cases);
            return ExitCode::FAILURE;
        }
    };

    let colors = rbtdre_detect_colors();
    let result = match rbtdre_run_single_case(case, &colors, &root_temp) {
        Ok(r) => r,
        Err(msg) => {
            eprintln!("rbtd: case execution error: {}", msg);
            return ExitCode::FAILURE;
        }
    };

    rbtdre_print_summary(&result, &colors);

    if result.failed > 0 {
        ExitCode::FAILURE
    } else {
        ExitCode::SUCCESS
    }
}

fn list_fixtures() {
    eprintln!("available fixtures:");
    for f in RBTDRC_FIXTURES {
        eprintln!("  {}", f.name);
    }
}

